<?php use function App\Core\{e,url,csrf_field}; ?><section class="card"><h2>商品検索</h2><form class="inline" method="post" action="<?= e(url('/products/search')) ?>"><?= csrf_field() ?><select name="service"><option value="fanza">FANZA</option><option value="sokmil">ソクミル</option><option value="duga">DUGA</option></select><input name="keyword" placeholder="キーワード"><button class="primary">検索</button></form></section><?php if($results): ?><section class="card"><h2>検索結果</h2><div class="cards"><?php foreach($results as $i=>$p): ?><article><img src="<?= e($p['image_url']??'') ?>" alt=""><h3><?= e($p['title']) ?></h3><p><?= e($p['service']) ?> / <?= e($p['genre']??'') ?></p><form method="post" action="<?= e(url('/products/save')) ?>"><?= csrf_field() ?><input type="hidden" name="index" value="<?= $i ?>"><button>保存</button></form></article><?php endforeach; ?></div></section><?php endif; ?><section class="card"><h2>保存済み商品</h2><div class="table-wrap"><table><tr><th>ID</th><th>サービス</th><th>タイトル</th><th>女優</th><th>ジャンル</th></tr><?php foreach($products as $p): ?><tr><td><?= $p['id'] ?></td><td><?= e($p['service']) ?></td><td><?= e($p['title']) ?></td><td><?= e($p['actress']) ?></td><td><?= e($p['genre']) ?></td></tr><?php endforeach; ?></table></div></section>
